<?php
namespace App\Services\Inventory;
use App\Models\BatchAssignment; use App\Models\Inventory\StockBalance; use App\Models\Inventory\StockBatchBalance; use App\Models\Inventory\StockMovement; use App\Models\Item; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class BatchAssignmentService {
 public function post(BatchAssignment $assignment): BatchAssignment { return DB::transaction(function() use($assignment) { $assignment=BatchAssignment::with('lines.item')->lockForUpdate()->findOrFail($assignment->id); if($assignment->status!==BatchAssignment::DRAFT) throw ValidationException::withMessages(['status'=>'Only draft assignments can be posted.']); if(StockMovement::where('reference_type',BatchAssignment::class)->where('reference_id',$assignment->id)->exists()) throw ValidationException::withMessages(['status'=>'Batch assignment movements already exist.']); foreach($assignment->lines as $line){$item=$line->item; if(! $item->is_batch_tracked) throw ValidationException::withMessages(['lines'=>'Only batch-tracked items can be assigned.']); $balance=StockBalance::where('warehouse_id',$assignment->warehouse_id)->where('item_id',$line->item_id)->lockForUpdate()->firstOrFail(); $total=(float)($balance->qty_on_hand?:$balance->quantity_on_hand?:0); $batchTotal=(float)StockBatchBalance::where('warehouse_id',$assignment->warehouse_id)->where('item_id',$line->item_id)->lockForUpdate()->sum('qty_on_hand'); $qty=(float)$line->quantity; if($qty<=0||$qty>$total-$batchTotal+0.000001) throw ValidationException::withMessages(['lines'=>'Assignment quantity exceeds unallocated legacy stock.']); $dest=StockBatchBalance::where('warehouse_id',$assignment->warehouse_id)->where('item_id',$line->item_id)->where('batch_no',$line->destination_batch_no)->where(fn($q)=>$line->destination_expiry_date?$q->whereDate('expiry_date',$line->destination_expiry_date):$q->whereNull('expiry_date'))->lockForUpdate()->first(); if($dest){$dest->increment('qty_on_hand',$qty);$dest->increment('qty_available',$qty);}else{$dest=StockBatchBalance::create(['company_id'=>$assignment->company_id,'branch_id'=>$assignment->branch_id,'warehouse_id'=>$assignment->warehouse_id,'item_id'=>$line->item_id,'batch_no'=>$line->destination_batch_no,'expiry_date'=>$line->destination_expiry_date,'qty_on_hand'=>$qty,'qty_reserved'=>0,'qty_available'=>$qty]);} foreach([['type'=>'BATCH_ASSIGNMENT_OUT','move'=>'OUT','batch'=>null],['type'=>'BATCH_ASSIGNMENT_IN','move'=>'IN','batch'=>$line->destination_batch_no]] as $m){StockMovement::create(['company_id'=>$assignment->company_id,'branch_id'=>$assignment->branch_id,'warehouse_id'=>$assignment->warehouse_id,'item_id'=>$line->item_id,'uom_id'=>$line->uom_id?:$item->base_unit_id,'base_uom_id'=>$item->base_unit_id,'transaction_type'=>$m['type'],'transaction_id'=>$assignment->id,'transaction_number'=>$assignment->number,'transaction_date'=>$assignment->assignment_date,'movement_type'=>$m['move'],'qty'=>$qty,'base_qty'=>$qty,'quantity_in'=>$m['move']==='IN'?$qty:0,'quantity_out'=>$m['move']==='OUT'?$qty:0,'batch_no'=>$m['batch'],'expiry_date'=>$m['move']==='IN'?$line->destination_expiry_date:null,'reference_type'=>BatchAssignment::class,'reference_id'=>$assignment->id,'reference_number'=>$assignment->number,'movement_date'=>$assignment->assignment_date,'remarks'=>'Legacy No Batch assignment','created_by'=>Auth::id(),'updated_by'=>Auth::id()]);}} $assignment->update(['status'=>BatchAssignment::POSTED,'posted_at'=>now(),'posted_by'=>Auth::id()]); return $assignment;});}
}
